<?php require_once __DIR__.'/../../includes/bootstrap.php'; require_login(); use app\Services\BookService; $svc=new BookService(); $errors=[]; $row=[]; if('edit'==='edit'){ $id=(int)($_GET['id']??0); $row=$svc->find($id); if(!$row) include PUBLIC_PATH.'/404.php'; } if($_SERVER['REQUEST_METHOD']==='POST'){ $r=('edit'==='edit')?$svc->save($_POST,$id):$svc->save($_POST); if($r['ok']){ flash('success','Đã lưu sách'); redirect_to('books/index.php'); } $errors=$r['errors']??[]; $row=array_merge($row,$_POST); } $title='Sửa sách'; include ROOT_PATH.'/includes/header.php'; ?><h1 class='h3 mb-3'>Sửa sách</h1><?php use app\Services\BookTypeService; $types=(new BookTypeService())->all(); ?><div class="card"><div class="card-body"><form method="post" class="row g-3"><div class="col-md-4"><label class="form-label required">ISBN</label><input name="isbn" class="form-control" value="<?= e($row['isbn']??'') ?>"><div class="text-danger small"><?= e($errors['isbn']??'') ?></div></div><div class="col-md-8"><label class="form-label required">Tên sách</label><input name="title" class="form-control" value="<?= e($row['title']??'') ?>"><div class="text-danger small"><?= e($errors['title']??'') ?></div></div><div class="col-md-4"><label class="form-label required">Loại sách</label><select name="book_type_id" class="form-select"><option value="">-- Chọn --</option><?php foreach($types as $t): ?><option value="<?= $t['id'] ?>" <?= selected($row['book_type_id']??'', $t['id']) ?>><?= e($t['name']) ?></option><?php endforeach; ?></select><div class="text-danger small"><?= e($errors['book_type_id']??'') ?></div></div><div class="col-md-4"><label class="form-label required">Tác giả</label><input name="author" class="form-control" value="<?= e($row['author']??'') ?>"><div class="text-danger small"><?= e($errors['author']??'') ?></div></div><div class="col-md-4"><label class="form-label">Nhà xuất bản</label><input name="publisher" class="form-control" value="<?= e($row['publisher']??'') ?>"></div><div class="col-md-3"><label class="form-label">Năm XB</label><input type="number" name="publish_year" class="form-control" value="<?= e($row['publish_year']??'') ?>"></div><div class="col-md-3"><label class="form-label required">Số lượng</label><input type="number" min="0" name="quantity" class="form-control" value="<?= e($row['quantity']??0) ?>"><div class="text-danger small"><?= e($errors['quantity']??'') ?></div></div><div class="col-md-3"><label class="form-label">Giá</label><input type="number" min="0" name="price" class="form-control" value="<?= e($row['price']??0) ?>"></div><div class="col-12"><label class="form-label">Mô tả</label><textarea name="description" class="form-control"><?= e($row['description']??'') ?></textarea></div><div class="col-12"><button class="btn btn-primary">Lưu</button> <a class="btn btn-secondary" href="index.php">Quay lại</a></div></form></div></div><?php include ROOT_PATH.'/includes/footer.php'; ?>
